uv run python -c "import os, hashlib, itertools, math
from pathlib import Path
root = Path('uploads/project_files')
now = __import__('time').time()
cutoff = now - 30*24*60*60
recent_py = 0
largest_size = -1
largest_path = None
log_error_count = 0
hash_to_files = {}
for dirpath, _, filenames in os.walk(root):
    for fn in filenames:
        p = Path(dirpath) / fn
        try:
            st = p.stat()
        except OSError:
            continue
        rel = p.relative_to(root).as_posix()
        if p.suffix.lower() == '.py' and st.st_mtime >= cutoff:
            recent_py += 1
        if st.st_size > largest_size:
            largest_size = st.st_size
            largest_path = rel
        if p.suffix.lower() == '.log':
            try:
                found = False
                with p.open('rb') as f:
                    while True:
                        chunk = f.read(1024*1024)
                        if not chunk:
                            break
                        if b'ERROR' in chunk:
                            found = True
                            break
                if found:
                    log_error_count += 1
            except OSError:
                pass
        try:
            h = hashlib.md5()
            with p.open('rb') as f:
                for chunk in iter(lambda: f.read(1024*1024), b''):
                    h.update(chunk)
            digest = h.hexdigest()
            hash_to_files.setdefault(digest, []).append(rel)
        except OSError:
            pass
dup_pairs = 0
for files in hash_to_files.values():
    n = len(files)
    if n > 1:
        dup_pairs += n*(n-1)//2
print(f'RecentPyFileCount: {recent_py}')
print(f'LargestFilePath: {largest_path} ({largest_size} bytes)')
print(f'LogFilesWithError: {log_error_count}')
print(f'DuplicateFilePairs: {dup_pairs}')"
